import pytest
from source import mergesort

def test_single_element_no_infinite_recursion():
    try:
        result = mergesort([1])
    except RecursionError:
        pytest.fail("mergesort([1]) caused infinite recursion — base case must handle len(arr) <= 1, not just len(arr) == 0")
    assert result == [1], f"mergesort([1]) should return [1], got {result}"
